import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./AdminDashboard.css";

const AdminDashboard = () => {
  const navigate = useNavigate();

  const [products, setProducts] = useState([]);
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activePage, setActivePage] = useState("");

  /* ===== LOGOUT ===== */
  const logout = () => {
    localStorage.removeItem("adminToken");
    navigate("/admin/login");
  };

  /* ===== FETCH FUNCTIONS ===== */
  const fetchProducts = async () => {
    setLoading(true);
    setActivePage("products");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/products");
      setProducts(res.data);
    } catch (err) {
      console.error(err);
      setProducts([]);
    }
    setLoading(false);
  };

  const fetchUsers = async () => {
    setLoading(true);
    setActivePage("users");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/users");
      setUsers(res.data);
    } catch (err) {
      console.error(err);
      setUsers([]);
    }
    setLoading(false);
  };

  const fetchOrders = async () => {
    setLoading(true);
    setActivePage("orders");
    try {
      const res = await axios.get("http://localhost:5000/api/admin/orders");
      setOrders(res.data);
    } catch (err) {
      console.error(err);
      setOrders([]);
    }
    setLoading(false);
  };

  /* ===== PRODUCT CRUD ===== */
  const [newProduct, setNewProduct] = useState({
    name: "",
    price: "",
    stock: 50,
    category: "",
    image: null,
  });

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    setNewProduct({
      ...newProduct,
      [name]: files ? files[0] : value,
    });
  };

  const addProduct = async (e) => {
    e.preventDefault();

    const formData = new FormData();
    formData.append("name", newProduct.name);
    formData.append("price", newProduct.price);
    formData.append("stock", newProduct.stock);
    formData.append("category", newProduct.category);
    formData.append("image", newProduct.image);

    try {
      await axios.post(
        "http://localhost:5000/api/admin/products",
        formData,
        { headers: { "Content-Type": "multipart/form-data" } }
      );
      alert("Product added successfully");
      setNewProduct({ name: "", price: "", stock: 50, category: "", image: null });
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("Failed to add product");
    }
  };

  const deleteProduct = async (id) => {
    if (!window.confirm("Delete this product?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/admin/products/${id}`);
      fetchProducts();
    } catch (err) {
      console.error(err);
    }
  };

  /* ===== PAGES ===== */
  const ProductsPage = () => (
    <>
      <h2>Products</h2>

      <form className="product-form" onSubmit={addProduct}>
        <input name="name" placeholder="Name" value={newProduct.name} onChange={handleChange} required />
        <input name="price" type="number" placeholder="Price" value={newProduct.price} onChange={handleChange} required />
        <input name="stock" type="number" placeholder="Stock" value={newProduct.stock} onChange={handleChange} />
        <input name="category" placeholder="Category" value={newProduct.category} onChange={handleChange} />
        <input name="image" type="file" accept="image/*" onChange={handleChange} required />
        <button type="submit">Add Product</button>
      </form>

      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th><th>Name</th><th>Price</th><th>Stock</th><th>Category</th><th>Image</th><th>Action</th>
          </tr>
        </thead>
        <tbody>
          {products.map((p) => (
            <tr key={p.id}>
              <td>{p.id}</td>
              <td>{p.name}</td>
              <td>{p.price}</td>
              <td>{p.stock}</td>
              <td>{p.category}</td>
              <td>
                <img
                  src={`http://localhost:5000/uploads/${p.image}`}
                  alt={p.name}
                  width="50"
                />
              </td>
              <td>
                <button onClick={() => deleteProduct(p.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  const UsersPage = () => (
    <>
      <h2>Users</h2>
      <table className="admin-table">
        <thead>
          <tr><th>ID</th><th>Name</th><th>Email</th></tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.full_name}</td>
              <td>{u.email}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  const OrdersPage = () => (
    <>
      <h2>Orders</h2>
      <table className="admin-table">
        <thead>
          <tr><th>ID</th><th>User</th><th>Total</th><th>Status</th></tr>
        </thead>
        <tbody>
          {orders.map((o) => (
            <tr key={o.id}>
              <td>{o.id}</td>
              <td>{o.full_name}</td>
              <td>{o.total_amount}</td>
              <td>{o.payment_status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );

  /* ===== UI ===== */
  return (
    <div className="admin-layout">
      <aside className="admin-sidebar">
        <h2 className="logo">ShopAdmin</h2>
        <button className="nav-link" onClick={fetchProducts}>Products</button>
        <button className="nav-link" onClick={fetchOrders}>Orders</button>
        <button className="nav-link" onClick={fetchUsers}>Users</button>
        <button className="logout-btn" onClick={logout}>Logout</button>
      </aside>

      <main className="admin-content">
        {loading && <p className="loading-text">Loading...</p>}
        {!loading && activePage === "products" && <ProductsPage />}
        {!loading && activePage === "users" && <UsersPage />}
        {!loading && activePage === "orders" && <OrdersPage />}
        {!loading && !activePage && <p>Welcome to Admin Dashboard</p>}
      </main>
    </div>
  );
};

export default AdminDashboard;
